final GlobalKey<NavigatorState> appNavigatorKey =
    GlobalKey<NavigatorState>();

UserSession? currentAppSession;

void setupNotificationTapHandler() {
  if (kIsWeb) return;

  FirebaseMessaging.onMessageOpenedApp.listen((RemoteMessage message) {
    handleNotificationTap(message.data);
  });

  FirebaseMessaging.instance.getInitialMessage().then((message) {
    if (message == null) return;

    Future.delayed(const Duration(seconds: 2), () {
      handleNotificationTap(message.data);
    });
  });
}

Future<void> handleNotificationTap(Map<String, dynamic> data) async {
  final type = (data['type'] ?? '').toString();
  final tableId = (data['tableId'] ?? '').toString();
  final chatId = (data['chatId'] ?? '').toString();

  if (type == 'new_table' && tableId.isNotEmpty) {
    await openTableFromNotification(tableId);
    return;
  }

  if (type == 'chat' && chatId.isNotEmpty) {
    await openChatFromNotification(chatId);
    return;
  }
}

Future<void> openTableFromNotification(String tableId) async {
  final session = currentAppSession;
  final navigator = appNavigatorKey.currentState;

  if (session == null || navigator == null) return;

  final tableSnap = await FirebaseFirestore.instance
      .collection('tables')
      .doc(tableId)
      .get();

  final tableData = tableSnap.data();
  if (tableData == null) return;

  navigator.push(
    MaterialPageRoute(
      builder: (_) => TableDetailPage(
        session: session,
        table: TableData.fromMap(tableData),
        tableId: tableId,
      ),
    ),
  );
}

Future<void> openChatFromNotification(String chatId) async {
  final navigator = appNavigatorKey.currentState;
  final currentUid = FirebaseAuth.instance.currentUser?.uid ?? '';

  if (navigator == null || currentUid.isEmpty) return;

  final chatSnap = await FirebaseFirestore.instance
      .collection('direct_chats')
      .doc(chatId)
      .get();

  final chatData = chatSnap.data();
  if (chatData == null) return;

  final memberUids = List<String>.from(chatData['memberUids'] ?? []);
  final otherUid = memberUids.firstWhere(
    (uid) => uid != currentUid,
    orElse: () => '',
  );

  if (otherUid.isEmpty) return;

  final otherUserSnap = await FirebaseFirestore.instance
      .collection('users')
      .doc(otherUid)
      .get();

  final otherData = otherUserSnap.data() ?? {};

  navigator.push(
    MaterialPageRoute(
      builder: (_) => ChatRoomPage(
        chatId: chatId,
        otherUid: otherUid,
        otherDisplayName:
            (otherData['displayName'] ?? 'Friend').toString(),
        otherPhotoUrl:
            (otherData['photoUrl'] ?? '').toString(),
        otherNickname: null,
      ),
    ),
  );
}

Future<void> setupPushNotifications() async {
  if (kIsWeb) return;

  final user = FirebaseAuth.instance.currentUser;
  if (user == null) return;

  final userRef = FirebaseFirestore.instance.collection('users').doc(user.uid);
  final messaging = FirebaseMessaging.instance;

  try {
    final settings = await messaging.requestPermission(
      alert: true,
      badge: true,
      sound: true,
      provisional: false,
    );

    await messaging.setForegroundNotificationPresentationOptions(
      alert: true,
      badge: true,
      sound: true,
    );

    await userRef.set({
      'fcmDebug_permission': settings.authorizationStatus.toString(),
      'fcmDebug_updatedAt': FieldValue.serverTimestamp(),
    }, SetOptions(merge: true));

    String? apnsToken;

    if (defaultTargetPlatform == TargetPlatform.iOS) {
      for (int i = 0; i < 60; i++) {
        apnsToken = await messaging.getAPNSToken();
      
        if (apnsToken != null && apnsToken.isNotEmpty) {
          break;
        }
      
        await Future.delayed(const Duration(seconds: 1));
      }

      await userRef.set({
        'apnsTokenDebug': apnsToken ?? 'NULL',
        'apnsTokenDebugUpdatedAt': FieldValue.serverTimestamp(),
      }, SetOptions(merge: true));
    }

    if (defaultTargetPlatform == TargetPlatform.iOS &&
        (apnsToken == null || apnsToken.isEmpty)) {
      return;
    }

    final token = await messaging.getToken();

    await userRef.set({
      'fcmTokenDebug': token ?? 'NULL',
      'fcmTokenDebugUpdatedAt': FieldValue.serverTimestamp(),
      'updatedAt': FieldValue.serverTimestamp(),
    }, SetOptions(merge: true));

    if (token != null && token.isNotEmpty) {
      await userRef.set({
        'fcmTokens': FieldValue.arrayUnion([token]),
        'updatedAt': FieldValue.serverTimestamp(),
      }, SetOptions(merge: true));
    }

    FirebaseMessaging.instance.onTokenRefresh.listen((newToken) async {
      final refreshedUser = FirebaseAuth.instance.currentUser;
      if (refreshedUser == null) return;

      await FirebaseFirestore.instance
          .collection('users')
          .doc(refreshedUser.uid)
          .set({
        'fcmTokenDebug': newToken,
        'fcmTokenDebugUpdatedAt': FieldValue.serverTimestamp(),
        'fcmTokens': FieldValue.arrayUnion([newToken]),
        'updatedAt': FieldValue.serverTimestamp(),
      }, SetOptions(merge: true));
    });
  } catch (e) {
    await userRef.set({
      'fcmDebugError': e.toString(),
      'fcmDebugErrorAt': FieldValue.serverTimestamp(),
    }, SetOptions(merge: true));
  }
}

Future<void> main() async {
  WidgetsFlutterBinding.ensureInitialized();

  await Firebase.initializeApp(
    options: DefaultFirebaseOptions.currentPlatform,
  );

  // 🔥🔥🔥 加這一行（超重要）
  await Future.delayed(const Duration(seconds: 2));
  setupPushNotifications();
  setupNotificationTapHandler();

  runApp(const PokerReservationApp());
}

Future<void> setupPush() async {
  FirebaseMessaging messaging = FirebaseMessaging.instance;

  // 權限
  NotificationSettings settings = await messaging.requestPermission(
    alert: true,
    badge: true,
    sound: true,
  );

  debugPrint('Permission: ${settings.authorizationStatus}');

  // 🔥🔥🔥 等 APNS token（關鍵）
  String? apnsToken;

  for (int i = 0; i < 30; i++) {
    apnsToken = await messaging.getAPNSToken();

    if (apnsToken != null && apnsToken.isNotEmpty) {
      break;
    }

    await Future.delayed(const Duration(seconds: 1));
  }

  debugPrint('APNS TOKEN: $apnsToken');

  // FCM token
  final fcmToken = await messaging.getToken();
  debugPrint('FCM TOKEN: $fcmToken');
}

