class AppThemeController extends InheritedWidget {
  final Function(bool isDark) updateTheme;

  const AppThemeController({
    super.key,
    required this.updateTheme,
    required super.child,
  });

  static AppThemeController of(BuildContext context) {
    final result = context
        .dependOnInheritedWidgetOfExactType<AppThemeController>();

    return result!;
  }

  @override
  bool updateShouldNotify(AppThemeController oldWidget) {
    return true;
  }
}

class AppLanguageController extends InheritedWidget {
  final String languageCode;
  final Function(String languageCode) updateLanguage;

  const AppLanguageController({
    super.key,
    required this.languageCode,
    required this.updateLanguage,
    required super.child,
  });

  static AppLanguageController of(BuildContext context) {
    final result =
        context.dependOnInheritedWidgetOfExactType<AppLanguageController>();
    return result!;
  }

  @override
  bool updateShouldNotify(AppLanguageController oldWidget) {
    return oldWidget.languageCode != languageCode;
  }
}

