class _PokerReservationAppState
    extends State<PokerReservationApp> {

  ThemeMode _themeMode = ThemeMode.light;

  String _languageCode = 'en';

  StreamSubscription<User?>? _authSub;

  @override
  void initState() {
    super.initState();

    _authSub = FirebaseAuth.instance.authStateChanges().listen((user) {
      if (user != null) {
        _loadSettings();
      }
    });
  }

  Future<void> _loadSettings() async {
    final user = FirebaseAuth.instance.currentUser;

    if (user == null) return;

    final doc = await FirebaseFirestore.instance
        .collection('users')
        .doc(user.uid)
        .get();

    final data = doc.data() ?? {};

    final isDark = data['darkMode'] == true;

    final languageCode =
        (data['languageCode'] ?? 'en').toString();

    if (!mounted) return;

    setState(() {
      _themeMode =
          isDark ? ThemeMode.dark : ThemeMode.light;

      _languageCode = languageCode;
    });
  }

  void updateTheme(bool isDark) {
    setState(() {
      _themeMode =
          isDark ? ThemeMode.dark : ThemeMode.light;
    });
  }

  void updateLanguage(String languageCode) {
    setState(() {
      _languageCode = languageCode;
    });
  }

  @override
  void dispose() {
    _authSub?.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return AppThemeController(
      updateTheme: updateTheme,
      child: AppLanguageController(
        languageCode: _languageCode,
        updateLanguage: updateLanguage,
        child: MaterialApp(
          navigatorKey: appNavigatorKey,
          title: 'Poker Table Reservation',
          debugShowCheckedModeBanner: false,

          themeMode: _themeMode,

          theme: ThemeData(
            useMaterial3: true,
            colorSchemeSeed: Colors.green,
            scaffoldBackgroundColor: const Color(0xFFF4F6F8),
            brightness: Brightness.light,
          ),

          darkTheme: ThemeData(
            useMaterial3: true,
            colorSchemeSeed: Colors.green,
            brightness: Brightness.dark,
            scaffoldBackgroundColor: const Color(0xFF111827),
            cardColor: const Color(0xFF1F2937),
          ),

          home: const AuthGate(),
        ),
      ),
    );
  }
}

class AuthGate extends StatelessWidget {
  const AuthGate({super.key});

  Future<UserSession?> _loadSession() async {
    final user = FirebaseAuth.instance.currentUser;
    if (user == null) return null;
  
    await ensureUserProfile(user);
    await setupPushNotifications();
  
    final userDoc = await FirebaseFirestore.instance
        .collection('users')
        .doc(user.uid)
        .get();

    final data = userDoc.data();
    if (data == null) return null;
  
    final name =
        (data['displayName'] ?? user.displayName ?? user.email ?? 'User')
            .toString();

    final roleText = (data['role'] ?? 'player').toString();
    final role = roleText == 'host' ? UserRole.host : UserRole.player;
  
    return UserSession(
      name: name,
      shortName: (data['shortName'] ?? name).toString(),
      role: role,
    );
  }

  @override
  Widget build(BuildContext context) {
    return StreamBuilder<User?>(
      stream: FirebaseAuth.instance.authStateChanges(),
      builder: (context, authSnapshot) {
        if (authSnapshot.connectionState == ConnectionState.waiting) {
          return const Scaffold(
            body: Center(child: CircularProgressIndicator()),
          );
        }

        final user = authSnapshot.data;

        if (user == null) {
          return const LoginPage();
        }

        return FutureBuilder<UserSession?>(
          future: _loadSession(),
          builder: (context, sessionSnapshot) {
            if (sessionSnapshot.connectionState == ConnectionState.waiting) {
              return const Scaffold(
                body: Center(child: CircularProgressIndicator()),
              );
            }

            if (sessionSnapshot.hasError || sessionSnapshot.data == null) {
              return const LoginPage();
            }

            currentAppSession = sessionSnapshot.data!;
            return TableListPage(session: sessionSnapshot.data!);
          },
        );
      },
    );
  }
}

