        ),
      );
      return;
    }
  
    try {
      final cred = await FirebaseAuth.instance.signInWithEmailAndPassword(
        email: email,
        password: password,
      );
  
      final user = cred.user;
      if (user == null) {
        _showSnack(
          tr(
            context,
            'Login failed',
            zhTw: '登入失敗',
            zhCn: '登录失败',
