  bool get _isApplePlatform {
    if (kIsWeb) return false;
    return defaultTargetPlatform == TargetPlatform.iOS ||
        defaultTargetPlatform == TargetPlatform.macOS;
  }

  bool get _showGoogleLogin {
    if (kIsWeb) return true;
    return defaultTargetPlatform == TargetPlatform.android ||
        defaultTargetPlatform == TargetPlatform.iOS;
  }

  Future<void> _signInWithApple() async {
    try {
      if (!await SignInWithApple.isAvailable()) {
        _showSnack('Apple Sign-In is not available on this device');
        return;
      }

      final appleProvider = AppleAuthProvider();
      appleProvider.addScope('email');
      appleProvider.addScope('name');

      final userCredential =
          await FirebaseAuth.instance.signInWithProvider(appleProvider);

      final user = userCredential.user;
      if (user == null) {
        _showSnack('Apple login failed: user is null');
        return;
      }

      final userRef =
          FirebaseFirestore.instance.collection('users').doc(user.uid);

      final userDoc = await userRef.get();
      final data = userDoc.data();

      if (data == null) {
        if (!mounted) return;

        Navigator.of(context).pushReplacement(
          MaterialPageRoute(
            builder: (_) => GoogleFirstSetupPage(user: user),
          ),
        );
        return;
      }

      await ensureUserProfile(user);
      await setupPushNotifications();

      final name =
          (data['displayName'] ?? user.displayName ?? user.email ?? 'User')
              .toString();

      final roleText = (data['role'] ?? 'player').toString();
      final role = roleText == 'host' ? UserRole.host : UserRole.player;

      if (!mounted) return;

      Navigator.of(context).pushReplacement(
        MaterialPageRoute(
          builder: (_) => TableListPage(
            session: UserSession(
              name: name,
              shortName: (data['shortName'] ?? name).toString(),
              role: role,
            ),
          ),
        ),
      );
    } on FirebaseAuthException catch (e, st) {
      debugPrint('APPLE FIREBASE AUTH ERROR');
      debugPrint('code: ${e.code}');
      debugPrint('message: ${e.message}');
      debugPrintStack(stackTrace: st);
      _showSnack('Apple login failed: ${e.code}');
    } catch (e, st) {
      debugPrint('APPLE LOGIN UNKNOWN ERROR: $e');
      debugPrintStack(stackTrace: st);
      _showSnack('Apple login failed: $e');
    }
  }

  Future<void> _signInWithGoogle() async {
    try {
      UserCredential userCredential;
  
      if (kIsWeb) {
        final googleProvider = GoogleAuthProvider();
        userCredential =
            await FirebaseAuth.instance.signInWithPopup(googleProvider);
      } else {
        final GoogleSignIn googleSignIn = GoogleSignIn();
  
        final GoogleSignInAccount? googleUser = await googleSignIn.signIn();
  
        if (googleUser == null) {
          _showSnack(
            tr(
              context,
              'Google sign-in cancelled',
              zhTw: '已取消 Google 登入',
              zhCn: '已取消 Google 登录',
              ko: 'Google 로그인이 취소되었습니다',
              ja: 'Googleログインがキャンセルされました',
              de: 'Google-Anmeldung abgebrochen',
              fr: 'Connexion Google annulée',
              ar: 'تم إلغاء تسجيل الدخول عبر Google',
              ru: 'Вход через Google отменён',
              trk: 'Google girişi iptal edildi',
              es: 'Inicio de sesión con Google cancelado',
              it: 'Accesso Google annullato',
              pl: 'Logowanie Google anulowane',
              pt: 'Login do Google cancelado',
              th: 'ยกเลิกการเข้าสู่ระบบ Google',
              id: 'Login Google dibatalkan',
              hi: 'Google लॉगिन रद्द किया गया',
              bn: 'Google লগইন বাতিল হয়েছে',
            ),
          );
          return;
        }
  
        final GoogleSignInAuthentication googleAuth =
            await googleUser.authentication;
  
        final credential = GoogleAuthProvider.credential(
          accessToken: googleAuth.accessToken,
          idToken: googleAuth.idToken,
        );
  
        userCredential = await FirebaseAuth.instance.signInWithCredential(
          credential,
        );
      }
  
      final user = userCredential.user;
      if (user == null) {
        _showSnack(
          tr(
            context,
            'Google login failed',
            zhTw: 'Google 登入失敗',
            zhCn: 'Google 登录失败',
            ko: 'Google 로그인 실패',
            ja: 'Googleログインに失敗しました',
            de: 'Google-Anmeldung fehlgeschlagen',
