            ru: 'Ошибка входа через Google',
            trk: 'Google girişi başarısız',
            es: 'Error al iniciar sesión con Google',
            it: 'Accesso Google non riuscito',
            pl: 'Logowanie Google nieudane',
            pt: 'Falha ao entrar com Google',
            th: 'เข้าสู่ระบบ Google ไม่สำเร็จ',
            id: 'Login Google gagal',
            hi: 'Google लॉगिन विफल',
            bn: 'Google লগইন ব্যর্থ হয়েছে',
          ),
        );
        return;
      }

      final userRef =
          FirebaseFirestore.instance.collection('users').doc(user.uid);

      final userDoc = await userRef.get();
      final data = userDoc.data();
      
      if (data == null) {
        if (!mounted) return;
      
        Navigator.of(context).pushReplacement(
          MaterialPageRoute(
            builder: (_) => GoogleFirstSetupPage(user: user),
          ),
        );
        return;
      }

      await ensureUserProfile(user);
      await setupPushNotifications();
      
      final name =
          (data['displayName'] ?? user.displayName ?? user.email ?? 'User')
              .toString();
  
      final roleText = (data['role'] ?? 'player').toString();
      final role = roleText == 'host' ? UserRole.host : UserRole.player;
  
      if (!mounted) return;
  
      Navigator.of(context).pushReplacement(
        MaterialPageRoute(
          builder: (_) => TableListPage(
            session: UserSession(
              name: name,
              shortName: (data['shortName'] ?? name).toString(),
              role: role,
            ),
          ),
        ),
      );
    } on FirebaseAuthException catch (e, st) {
      debugPrint('GOOGLE FIREBASE AUTH ERROR');
      debugPrint('code: ${e.code}');
      debugPrint('message: ${e.message}');
      debugPrintStack(stackTrace: st);

      _showSnack(
        '${tr(
          context,
          'Google login failed',
          zhTw: 'Google 登入失敗',
          zhCn: 'Google 登录失败',
          ko: 'Google 로그인 실패',
          ja: 'Googleログインに失敗しました',
          de: 'Google-Anmeldung fehlgeschlagen',
          fr: 'Échec de la connexion Google',
          ar: 'فشل تسجيل الدخول عبر Google',
          ru: 'Ошибка входа через Google',
