class GoogleFirstSetupPage extends StatefulWidget {
  final User user;

  const GoogleFirstSetupPage({
    super.key,
    required this.user,
  });

  @override
  State<GoogleFirstSetupPage> createState() => _GoogleFirstSetupPageState();
}

class _GoogleFirstSetupPageState extends State<GoogleFirstSetupPage> {
  late final TextEditingController displayNameController;
  final TextEditingController lastNameController = TextEditingController();

  bool isSaving = false;

  @override
  void initState() {
    super.initState();

    final defaultName =
        (widget.user.displayName != null &&
                widget.user.displayName!.trim().isNotEmpty)
            ? widget.user.displayName!.trim()
            : (widget.user.email?.split('@').first ?? 'User');

    displayNameController = TextEditingController(text: defaultName);
  }

  Future<void> _saveProfile() async {
    final displayName = displayNameController.text.trim();
    final lastName = lastNameController.text.trim();

    if (displayName.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            tr(
              context,
              'Please enter display name',
              zhTw: '請輸入顯示名稱',
              zhCn: '请输入显示名称',
              ko: '표시 이름을 입력하세요',
              ja: '表示名を入力してください',
              de: 'Bitte Anzeigenamen eingeben',
              fr: 'Veuillez saisir un nom d’affichage',
              ar: 'يرجى إدخال اسم العرض',
              ru: 'Введите отображаемое имя',
              trk: 'Lütfen görünen adı girin',
              es: 'Ingresa un nombre para mostrar',
              it: 'Inserisci il nome visualizzato',
              pl: 'Wpisz nazwę wyświetlaną',
              pt: 'Digite o nome de exibição',
              th: 'กรุณากรอกชื่อที่แสดง',
              id: 'Masukkan nama tampilan',
              hi: 'कृपया डिस्प्ले नाम दर्ज करें',
              bn: 'অনুগ্রহ করে প্রদর্শন নাম লিখুন',
            ),
          ),
        ),
      );
      return;
    }

    setState(() {
      isSaving = true;
    });

    try {
      final shortName = await saveUserProfileData(
        user: widget.user,
        displayName: displayName,
        lastName: lastName,
        role: UserRole.player,
      );

      await setupPushNotifications();

      if (!mounted) return;

      Navigator.of(context).pushAndRemoveUntil(
        MaterialPageRoute(
          builder: (_) => TableListPage(
            session: UserSession(
              name: displayName,
              shortName: shortName,
              role: UserRole.player,
            ),
          ),
        ),
        (route) => false,
      );
    } catch (e) {
      if (!mounted) return;

      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            tr(
              context,
              'Failed to save profile',
              zhTw: '儲存個人資料失敗',
              zhCn: '保存个人资料失败',
              ko: '프로필 저장 실패',
              ja: 'プロフィールの保存に失敗しました',
              de: 'Profil konnte nicht gespeichert werden',
              fr: 'Échec de l’enregistrement du profil',
              ar: 'فشل حفظ الملف الشخصي',
              ru: 'Не удалось сохранить профиль',
              trk: 'Profil kaydedilemedi',
              es: 'No se pudo guardar el perfil',
              it: 'Impossibile salvare il profilo',
              pl: 'Nie udało się zapisać profilu',
              pt: 'Falha ao salvar perfil',
              th: 'บันทึกโปรไฟล์ไม่สำเร็จ',
              id: 'Gagal menyimpan profil',
              hi: 'प्रोफ़ाइल सहेजने में विफल',
              bn: 'প্রোফাইল সংরক্ষণ ব্যর্থ হয়েছে',
            ),
          ),
        ),
      );

      setState(() {
        isSaving = false;
      });
    }
  }

  @override
  void dispose() {
    displayNameController.dispose();
    lastNameController.dispose();
    super.dispose();
  }

