            fr: 'S’inscrire',
            ar: 'إنشاء حساب',
            ru: 'Регистрация',
            trk: 'Kayıt Ol',
            es: 'Registrarse',
            it: 'Registrati',
            pl: 'Rejestracja',
            pt: 'Registrar',
            th: 'สมัครสมาชิก',
            id: 'Daftar',
            hi: 'रजिस्टर',
