class NewTableNotificationsPage extends StatelessWidget {
  const NewTableNotificationsPage({super.key});

  @override
  Widget build(BuildContext context) {
    final uid = FirebaseAuth.instance.currentUser?.uid ?? '';

    return Scaffold(
      appBar: AppBar(
        title: Text(
          tr(
            context,
            'Notifications',
            zhTw: '通知',
            zhCn: '通知',
            ko: '알림',
            ja: '通知',
            de: 'Benachrichtigungen',
            fr: 'Notifications',
            ar: 'الإشعارات',
            ru: 'Уведомления',
            trk: 'Bildirimler',
            es: 'Notificaciones',
            it: 'Notifiche',
            pl: 'Powiadomienia',
            pt: 'Notificações',
            th: 'การแจ้งเตือน',
            id: 'Notifikasi',
            hi: 'सूचनाएं',
            bn: 'নোটিফিকেশন',
          ),
        ),
      ),
      body: StreamBuilder<QuerySnapshot<Map<String, dynamic>>>(
        stream: FirebaseFirestore.instance
            .collection('notifications')
            .where('targetUserIds', arrayContains: uid)
            .orderBy('createdAt', descending: true)
            .snapshots(),
        builder: (context, snapshot) {
          final docs = snapshot.data?.docs ?? [];

          if (docs.isEmpty) {
            return Center(
              child: Text(
                tr(
                  context,
                  'No notifications',
                  zhTw: '目前沒有通知',
                  zhCn: '目前没有通知',
                  ko: '알림이 없습니다',
                  ja: '通知はありません',
                  de: 'Keine Benachrichtigungen',
                  fr: 'Aucune notification',
                  ar: 'لا توجد إشعارات',
                  ru: 'Нет уведомлений',
                  trk: 'Bildirim yok',
                  es: 'No hay notificaciones',
