  Future<void> _openChatFromFriendship(
    Map<String, dynamic> friendshipData,
  ) async {
    final currentUser = FirebaseAuth.instance.currentUser;
    if (currentUser == null) return;

    final userA = Map<String, dynamic>.from(friendshipData['userA'] ?? {});
    final userB = Map<String, dynamic>.from(friendshipData['userB'] ?? {});
    final nicknames = Map<String, dynamic>.from(
      friendshipData['nicknames'] ?? {},
    );

    final otherUser =
        (userA['uid'] ?? '').toString() == currentUser.uid ? userB : userA;

    final otherUid = (otherUser['uid'] ?? '').toString().trim();

    final blocked = await isBlockedEitherWay(
      currentUid: currentUser.uid,
      otherUid: otherUid,
    );

    if (blocked) {
      if (!mounted) return;

      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            tr(
              context,
              'This user is not available',
              zhTw: '這位使用者目前無法使用',
              zhCn: '这位用户目前不可用',
              ko: '이 사용자는 사용할 수 없습니다',
              ja: 'このユーザーは利用できません',
              de: 'Dieser Nutzer ist nicht verfügbar',
              fr: 'Cet utilisateur n’est pas disponible',
              ar: 'هذا المستخدم غير متاح',
              ru: 'Этот пользователь недоступен',
              trk: 'Bu kullanıcı kullanılamıyor',
              es: 'Este usuario no está disponible',
              it: 'Questo utente non è disponibile',
              pl: 'Ten użytkownik jest niedostępny',
              pt: 'Este usuário não está disponível',
              th: 'ผู้ใช้นี้ไม่พร้อมใช้งาน',
              id: 'Pengguna ini tidak tersedia',
              hi: 'यह यूज़र उपलब्ध नहीं है',
              bn: 'এই ব্যবহারকারী উপলব্ধ নয়',
            ),
          ),
        ),
      );
      return;
    }

    final myNickname = (nicknames[currentUser.uid] ?? '').toString().trim();

    if (!mounted) return;

    Navigator.of(context).push(
      MaterialPageRoute(
        builder: (_) => ChatRoomPage(
          chatId: (friendshipData['chatId'] ?? '').toString(),
          otherUid: otherUid,
          otherDisplayName: (otherUser['displayName'] ??
                  tr(
                    context,
                    'Chat',
                    zhTw: '聊天',
                    zhCn: '聊天',
                    ko: '채팅',
                    ja: 'チャット',
                    de: 'Chat',
                    fr: 'Chat',
                    ar: 'الدردشة',
                    ru: 'Чат',
                    trk: 'Sohbet',
                    es: 'Chat',
                    it: 'Chat',
                    pl: 'Czat',
                    pt: 'Chat',
                    th: 'แชท',
                    id: 'Chat',
                    hi: 'चैट',
                    bn: 'চ্যাট',
                  ))
              .toString(),
          otherPhotoUrl: (otherUser['photoUrl'] ?? '').toString(),
          otherNickname: myNickname,
        ),
      ),
    );
  }

