  Widget _buildFriendsList() {
    return forceLightTheme(
      Card(
        color: Colors.white,
        surfaceTintColor: Colors.white,
        child: Padding(
          padding: const EdgeInsets.all(16),
          child: StreamBuilder<DocumentSnapshot<Map<String, dynamic>>>(
            stream: FirebaseFirestore.instance
                .collection('users')
                .doc(currentUid)
                .snapshots(),
            builder: (context, userSnapshot) {
              final currentUserData = userSnapshot.data?.data() ?? {};
              final blockedUids = List<String>.from(
                currentUserData['blockedUids'] ?? [],
              );

              return StreamBuilder<QuerySnapshot<Map<String, dynamic>>>(
                stream: FirebaseFirestore.instance
                    .collection('friendships')
                    .where('memberUids', arrayContains: currentUid)
                    .snapshots(),
                builder: (context, snapshot) {
                  final docs = [...(snapshot.data?.docs ?? [])]
                      .where((doc) {
                        final data = doc.data();

                        final userA =
                            Map<String, dynamic>.from(data['userA'] ?? {});
                        final userB =
                            Map<String, dynamic>.from(data['userB'] ?? {});

                        final otherUser =
                            (userA['uid'] ?? '').toString() == currentUid
                                ? userB
                                : userA;

                        final otherUid =
                            (otherUser['uid'] ?? '').toString().trim();

                        return !blockedUids.contains(otherUid);
                      })
                      .toList()
                    ..sort((a, b) {
                      final aData = a.data();
                      final bData = b.data();

                      final aTime = aData['updatedAt'];
                      final bTime = bData['updatedAt'];

                      final aMillis =
                          aTime is Timestamp ? aTime.millisecondsSinceEpoch : 0;
                      final bMillis =
                          bTime is Timestamp ? bTime.millisecondsSinceEpoch : 0;

                      return bMillis.compareTo(aMillis);
                    });

                  if (docs.isEmpty) {
                    return Padding(
                      padding: const EdgeInsets.all(12),
                      child: Text(
                        tr(
                          context,
                          'No friends yet',
                          zhTw: '目前還沒有好友',
                          zhCn: '目前还没有好友',
                          ko: '아직 친구가 없습니다',
                          ja: 'まだ友達がいません',
                          de: 'Noch keine Freunde',
                          fr: 'Aucun ami pour le moment',
                          ar: 'لا يوجد أصدقاء بعد',
                          ru: 'Пока нет друзей',
                          trk: 'Henüz arkadaş yok',
                          es: 'Aún no hay amigos',
                          it: 'Ancora nessun amico',
                          pl: 'Nie masz jeszcze znajomych',
                          pt: 'Ainda não há amigos',
                          th: 'ยังไม่มีเพื่อน',
                          id: 'Belum ada teman',
                          hi: 'अभी कोई दोस्त नहीं है',
                          bn: 'এখনও কোনো বন্ধু নেই',
                        ),
                        style: const TextStyle(color: Colors.black54),
                      ),
                    );
                  }

                  return Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Text(
                        tr(
                          context,
                          'Friends',
                          zhTw: '好友',
                          zhCn: '好友',
                          ko: '친구',
                          ja: '友達',
                          de: 'Freunde',
                          fr: 'Amis',
                          ar: 'الأصدقاء',
                          ru: 'Друзья',
                          trk: 'Arkadaşlar',
                          es: 'Amigos',
                          it: 'Amici',
                          pl: 'Znajomi',
                          pt: 'Amigos',
                          th: 'เพื่อน',
                          id: 'Teman',
                          hi: 'दोस्त',
                          bn: 'বন্ধু',
                        ),
                        style: const TextStyle(
                          color: Colors.black87,
                          fontSize: 18,
                          fontWeight: FontWeight.w800,
                        ),
                      ),

                      const SizedBox(height: 12),

                      ...docs.map((doc) {
                        final data = doc.data();

                        final userA =
                            Map<String, dynamic>.from(data['userA'] ?? {});
                        final userB =
                            Map<String, dynamic>.from(data['userB'] ?? {});
                        final nicknames =
                            Map<String, dynamic>.from(data['nicknames'] ?? {});

                        final otherUser =
                            (userA['uid'] ?? '').toString() == currentUid
                                ? userB
                                : userA;

                        final otherUid =
                            (otherUser['uid'] ?? '').toString().trim();

                        final nickname =
                            (nicknames[currentUid] ?? '').toString().trim();

                        final displayName = nickname.isNotEmpty
                            ? nickname
                            : (otherUser['displayName'] ??
                                    tr(
                                      context,
                                      'Friend',
                                      zhTw: '好友',
                                      zhCn: '好友',
                                      ko: '친구',
                                      ja: '友達',
                                      de: 'Freund',
                                      fr: 'Ami',
                                      ar: 'صديق',
                                      ru: 'Друг',
                                      trk: 'Arkadaş',
                                      es: 'Amigo',
                                      it: 'Amico',
                                      pl: 'Znajomy',
                                      pt: 'Amigo',
                                      th: 'เพื่อน',
                                      id: 'Teman',
                                      hi: 'दोस्त',
                                      bn: 'বন্ধু',
                                    ))
                                .toString();

                        final subtitleName =
                            (otherUser['displayName'] ?? '')
                                .toString()
                                .trim();

                        final chatId = (data['chatId'] ?? '').toString();

                        return FutureBuilder<bool>(
                          future: isBlockedEitherWay(
                            currentUid: currentUid,
                            otherUid: otherUid,
                          ),
                          builder: (context, blockedSnapshot) {
                            if (blockedSnapshot.data == true) {
                              return const SizedBox();
                            }

                            return StreamBuilder<
                                DocumentSnapshot<Map<String, dynamic>>>(
                              stream: FirebaseFirestore.instance
                                  .collection('direct_chats')
                                  .doc(chatId)
                                  .snapshots(),
                              builder: (context, chatSnapshot) {
                                final chatData = chatSnapshot.data?.data() ?? {};
                                final unreadCounts = Map<String, dynamic>.from(
                                  chatData['unreadCounts'] ?? {},
                                );

                                final rawUnread =
                                    unreadCounts[currentUid] ?? 0;

                                final unreadCount = rawUnread is int
                                    ? rawUnread
                                    : int.tryParse(rawUnread.toString()) ?? 0;

                                return ListTile(
                                  contentPadding: EdgeInsets.zero,
                                  onTap: () => _openChatFromFriendship(data),
                                  leading: FutureBuilder<
                                      DocumentSnapshot<Map<String, dynamic>>>(
                                    future: FirebaseFirestore.instance
                                        .collection('users')
                                        .doc(otherUid)
                                        .get(),
                                    builder: (context, userSnap) {
                                      final userData =
                                          userSnap.data?.data() ?? otherUser;

                                      final avatar =
                                          resolveAvatarSnapshotFromMap(
                                        userData,
                                      );

                                      return buildAppAvatar(
                                        radius: 20,
                                        avatar: avatar,
                                        displayName: displayName,
                                        iconSize: 18,
                                        textSize: 14,
                                      );
                                    },
                                  ),
                                  title: Row(
                                    children: [
                                      Expanded(
                                        child: Text(
                                          displayName,
                                          style: const TextStyle(
                                            color: Colors.black87,
                                            fontWeight: FontWeight.w700,
                                          ),
                                          overflow: TextOverflow.ellipsis,
                                        ),
                                      ),
                                      if (unreadCount > 0)
                                        Container(
                                          margin:
                                              const EdgeInsets.only(left: 8),
                                          padding:
                                              const EdgeInsets.symmetric(
                                            horizontal: 8,
                                            vertical: 3,
                                          ),
                                          decoration: BoxDecoration(
                                            color: const Color(0xFFDC2626),
                                            borderRadius:
                                                BorderRadius.circular(999),
                                          ),
                                          constraints: const BoxConstraints(
                                            minWidth: 22,
                                            minHeight: 22,
                                          ),
                                          child: Text(
                                            unreadCount > 99
                                                ? '99+'
                                                : unreadCount.toString(),
                                            textAlign: TextAlign.center,
                                            style: const TextStyle(
                                              color: Colors.white,
                                              fontSize: 11,
                                              fontWeight: FontWeight.w800,
                                            ),
                                          ),
                                        ),
                                    ],
                                  ),
                                  subtitle: subtitleName.isNotEmpty &&
                                          subtitleName != displayName
                                      ? Text(
                                          subtitleName,
                                          style: const TextStyle(
                                            color: Colors.black54,
                                          ),
                                        )
                                      : Text(
                                          unreadCount > 0
                                              ? tr(
                                                  context,
                                                  '$unreadCount unread message${unreadCount > 1 ? 's' : ''}',
                                                  zhTw:
                                                      '$unreadCount 則未讀訊息',
                                                  zhCn:
                                                      '$unreadCount 条未读消息',
                                                  ko:
                                                      '읽지 않은 메시지 $unreadCount개',
                                                  ja:
                                                      '未読メッセージ $unreadCount 件',
                                                  de:
                                                      '$unreadCount ungelesene Nachricht${unreadCount > 1 ? 'en' : ''}',
                                                  fr:
                                                      '$unreadCount message${unreadCount > 1 ? 's' : ''} non lu${unreadCount > 1 ? 's' : ''}',
                                                  ar:
                                                      '$unreadCount رسالة غير مقروءة',
                                                  ru:
                                                      '$unreadCount непрочитанных сообщений',
                                                  trk:
                                                      '$unreadCount okunmamış mesaj',
                                                  es:
                                                      '$unreadCount mensaje${unreadCount > 1 ? 's' : ''} sin leer',
                                                  it:
                                                      '$unreadCount messagg${unreadCount > 1 ? 'i' : 'io'} non lett${unreadCount > 1 ? 'i' : 'o'}',
                                                  pl:
                                                      '$unreadCount nieprzeczytanych wiadomości',
                                                  pt:
                                                      '$unreadCount mensagem${unreadCount > 1 ? 'ens' : ''} não lida${unreadCount > 1 ? 's' : ''}',
                                                  th:
                                                      '$unreadCount ข้อความที่ยังไม่ได้อ่าน',
                                                  id:
                                                      '$unreadCount pesan belum dibaca',
                                                  hi:
                                                      '$unreadCount अपठित संदेश',
                                                  bn:
                                                      '$unreadCount টি অপঠিত বার্তা',
                                                )
                                              : tr(
                                                  context,
                                                  'Tap to open chat',
                                                  zhTw: '點擊開啟聊天',
                                                  zhCn: '点击打开聊天',
                                                  ko: '눌러서 채팅 열기',
                                                  ja: 'タップしてチャットを開く',
                                                  de: 'Tippen zum Öffnen des Chats',
                                                  fr: 'Touchez pour ouvrir le chat',
                                                  ar: 'اضغط لفتح الدردشة',
                                                  ru: 'Нажмите, чтобы открыть чат',
                                                  trk: 'Sohbeti açmak için dokun',
