class UnreadChatIconButton extends StatelessWidget {
  final VoidCallback onTap;

  const UnreadChatIconButton({
    super.key,
    required this.onTap,
  });

  @override
  Widget build(BuildContext context) {
    final currentUid = FirebaseAuth.instance.currentUser?.uid ?? '';

    if (currentUid.isEmpty) {
      return IconButton(
        onPressed: onTap,
        tooltip: tr(
          context,
          'Friends & Chat',
          zhTw: '好友與聊天',
          zhCn: '好友与聊天',
          ko: '친구 및 채팅',
          ja: '友達とチャット',
          de: 'Freunde & Chat',
          fr: 'Amis et chat',
          ar: 'الأصدقاء والدردشة',
          ru: 'Друзья и чат',
          trk: 'Arkadaşlar ve Sohbet',
          es: 'Amigos y chat',
          it: 'Amici e chat',
          pl: 'Znajomi i czat',
          pt: 'Amigos e chat',
          th: 'เพื่อนและแชท',
          id: 'Teman & Chat',
          hi: 'दोस्त और चैट',
          bn: 'বন্ধু ও চ্যাট',
        ),
        icon: const Icon(Icons.people_alt_outlined),
      );
    }

    return StreamBuilder<QuerySnapshot<Map<String, dynamic>>>(
      stream: FirebaseFirestore.instance
          .collection('direct_chats')
          .where('memberUids', arrayContains: currentUid)
          .snapshots(),
      builder: (context, snapshot) {
        int unreadTotal = 0;

        for (final doc
            in snapshot.data?.docs ??
                <QueryDocumentSnapshot<Map<String, dynamic>>>[]) {
          final data = doc.data();

          final unreadCounts =
              Map<String, dynamic>.from(data['unreadCounts'] ?? {});

          final count = (unreadCounts[currentUid] ?? 0);

          if (count is int) {
            unreadTotal += count;
          } else {
            unreadTotal += int.tryParse(count.toString()) ?? 0;
          }
        }

        return Stack(
          clipBehavior: Clip.none,
          children: [
            IconButton(
              onPressed: onTap,
              tooltip: tr(
                context,
                'Friends & Chat',
                zhTw: '好友與聊天',
                zhCn: '好友与聊天',
                ko: '친구 및 채팅',
                ja: '友達とチャット',
                de: 'Freunde & Chat',
                fr: 'Amis et chat',
                ar: 'الأ朋友 والدردشة',
                ru: 'Друзья и чат',
                trk: 'Arkadaşlar ve Sohbet',
                es: 'Amigos y chat',
                it: 'Amici e chat',
                pl: 'Znajomi i czat',
                pt: 'Amigos e chat',
                th: 'เพื่อนและแชท',
                id: 'Teman & Chat',
                hi: 'दोस्त और चैट',
                bn: 'বন্ধু ও চ্যাট',
              ),
              icon: const Icon(Icons.people_alt_outlined),
            ),

            if (unreadTotal > 0)
              Positioned(
                right: 6,
                top: 6,
                child: Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 6,
                    vertical: 2,
                  ),
                  decoration: BoxDecoration(
                    color: const Color(0xFFDC2626),
                    borderRadius: BorderRadius.circular(999),
                  ),
                  constraints: const BoxConstraints(
                    minWidth: 18,
                    minHeight: 18,
                  ),
                  child: Text(
                    unreadTotal > 99
                        ? '99+'
                        : unreadTotal.toString(),
                    textAlign: TextAlign.center,
                    style: const TextStyle(
                      color: Colors.white,
                      fontSize: 11,
                      fontWeight: FontWeight.w800,
                    ),
                  ),
                ),
              ),
          ],
        );
      },
    );
  }
}

