class ChatRoomPage extends StatefulWidget {
  final String chatId;
  final String otherUid;
  final String otherDisplayName;
  final String otherPhotoUrl;
  final String? otherNickname;

  const ChatRoomPage({
    super.key,
    required this.chatId,
    required this.otherUid,
    required this.otherDisplayName,
    required this.otherPhotoUrl,
    this.otherNickname,
  });

  @override
  State<ChatRoomPage> createState() => _ChatRoomPageState();
}

class _ChatRoomPageState extends State<ChatRoomPage> {
  final TextEditingController messageController = TextEditingController();
  final TextEditingController chatSearchController = TextEditingController();

  bool isSending = false;
  bool isSearchMode = false;
  String chatKeyword = '';

  @override
  void initState() {
    super.initState();
    _markChatAsRead();
  }

  Future<void> _markChatAsRead() async {
    final currentUid = FirebaseAuth.instance.currentUser?.uid ?? '';
    if (currentUid.isEmpty) return;

    try {
      await FirebaseFirestore.instance
          .collection('direct_chats')
          .doc(widget.chatId)
          .update({
        'unreadCounts.$currentUid': 0,
        'lastReadAt.$currentUid': FieldValue.serverTimestamp(),
        'updatedAt': FieldValue.serverTimestamp(),
      });
    } catch (e) {
      debugPrint('mark read error: $e');
    }
  }

  Future<void> _sendMessage() async {
    final currentUser = FirebaseAuth.instance.currentUser;
    if (currentUser == null) return;

    final text = messageController.text.trim();
    if (text.isEmpty) return;

    setState(() {
      isSending = true;
    });

    try {
      final currentUserDoc = await FirebaseFirestore.instance
          .collection('users')
          .doc(currentUser.uid)
          .get();

      final currentData = currentUserDoc.data() ?? {};
      final senderName =
          (currentData['displayName'] ??
                  currentUser.displayName ??
                  tr(
                    context,
                    'User',
                    zhTw: '使用者',
                    zhCn: '用户',
                    ko: '사용자',
                    ja: 'ユーザー',
                    de: 'Benutzer',
                    fr: 'Utilisateur',
                    ar: 'مستخدم',
                    ru: 'Пользователь',
                    trk: 'Kullanıcı',
                    es: 'Usuario',
                    it: 'Utente',
                    pl: 'Użytkownik',
                    pt: 'Usuário',
                    th: 'ผู้ใช้',
                    id: 'Pengguna',
                    hi: 'उपयोगकर्ता',
                    bn: 'ব্যবহারকারী',
                  ))
              .toString();

      final senderPhotoUrl =
          (currentData['photoUrl'] ?? currentUser.photoURL ?? '').toString();

      final chatRef = FirebaseFirestore.instance
          .collection('direct_chats')
          .doc(widget.chatId);

      final messageRef = chatRef.collection('messages').doc();

      await FirebaseFirestore.instance.runTransaction((tx) async {
        tx.set(messageRef, {
          'messageId': messageRef.id,
          'chatId': widget.chatId,
          'senderUid': currentUser.uid,
          'senderName': senderName,
          'senderPhotoUrl': senderPhotoUrl,
          'text': text,
          'createdAt': FieldValue.serverTimestamp(),
        });

        tx.set(chatRef, {
          'chatId': widget.chatId,
          'type': 'direct',
          'memberUids': [currentUser.uid, widget.otherUid],
          'lastMessage': text,
          'lastMessageAt': FieldValue.serverTimestamp(),
          'lastMessageSenderUid': currentUser.uid,
          'updatedAt': FieldValue.serverTimestamp(),
          'unreadCounts.${currentUser.uid}': 0,
          'unreadCounts.${widget.otherUid}': FieldValue.increment(1),
        }, SetOptions(merge: true));

        tx.set(
          FirebaseFirestore.instance.collection('friendships').doc(widget.chatId),
          {
            'updatedAt': FieldValue.serverTimestamp(),
          },
          SetOptions(merge: true),
        );
      });

      messageController.clear();

      await _markChatAsRead();
    } catch (e) {
      if (!mounted) return;

      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            tr(
              context,
              'Failed to send message',
              zhTw: '發送訊息失敗',
              zhCn: '发送消息失败',
              ko: '메시지 전송에 실패했습니다',
              ja: 'メッセージの送信に失敗しました',
              de: 'Nachricht konnte nicht gesendet werden',
              fr: 'Impossible d’envoyer le message',
              ar: 'فشل إرسال الرسالة',
              ru: 'Не удалось отправить сообщение',
              trk: 'Mesaj gönderilemedi',
              es: 'No se pudo enviar el mensaje',
              it: 'Impossibile inviare il messaggio',
              pl: 'Nie udało się wysłać wiadomości',
              pt: 'Falha ao enviar mensagem',
              th: 'ส่งข้อความไม่สำเร็จ',
              id: 'Gagal mengirim pesan',
              hi: 'संदेश भेजने में विफल',
              bn: 'বার্তা পাঠানো যায়নি',
            ),
          ),
        ),
      );
    }

    if (mounted) {
      setState(() {
        isSending = false;
      });
    }
  }

  Future<void> _copyMessage(String text) async {
    await Clipboard.setData(ClipboardData(text: text));

    if (!mounted) return;

    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text(
          tr(
            context,
            'Message copied',
            zhTw: '訊息已複製',
            zhCn: '消息已复制',
            ko: '메시지가 복사되었습니다',
            ja: 'メッセージをコピーしました',
            de: 'Nachricht kopiert',
            fr: 'Message copié',
            ar: 'تم نسخ الرسالة',
            ru: 'Сообщение скопировано',
            trk: 'Mesaj kopyalandı',
            es: 'Mensaje copiado',
            it: 'Messaggio copiato',
            pl: 'Wiadomość skopiowana',
            pt: 'Mensagem copiada',
            th: 'คัดลอกข้อความแล้ว',
            id: 'Pesan disalin',
            hi: 'संदेश कॉपी किया गया',
            bn: 'বার্তা কপি হয়েছে',
          ),
        ),
      ),
    );
  }

  @override
  void dispose() {
    _markChatAsRead();
    messageController.dispose();
    chatSearchController.dispose();
    super.dispose();
  }

