                            ),
                            constraints: const BoxConstraints(
                              maxWidth: 320,
                            ),
                            decoration: BoxDecoration(
                              color: isMine
                                  ? const Color(0xFFDDF6E3)
                                  : Colors.white,
                              borderRadius:
                                  BorderRadius.circular(16),
                              border: Border.all(
                                color: isMine
                                    ? const Color(0xFFBBE7C6)
                                    : const Color(0xFFE5E7EB),
                              ),
                              boxShadow: const [
                                BoxShadow(
                                  color: Color(0x12000000),
                                  blurRadius: 8,
                                  offset: Offset(0, 3),
                                ),
                              ],
                            ),
                            child: Column(
                              crossAxisAlignment:
                                  CrossAxisAlignment.start,
                              children: [
                                if (!isMine)
                                  Padding(
                                    padding:
                                        const EdgeInsets.only(
                                      bottom: 4,
                                    ),
                                    child: Text(
                                      (data['senderName'] ?? '')
                                          .toString(),
                                      style: const TextStyle(
                                        fontSize: 12,
                                        fontWeight:
                                            FontWeight.w700,
                                        color: Colors.black54,
                                      ),
