class TableDetailPage extends StatefulWidget {
  final UserSession session;
  final TableData table;
  final String tableId;

  const TableDetailPage({
    super.key,
    required this.session,
    required this.table,
    required this.tableId,
  });

  @override
  State<TableDetailPage> createState() => _TableDetailPageState();
}

class _TableDetailPageState extends State<TableDetailPage> {
  late final DocumentReference<Map<String, dynamic>> tableDocRef;

  StreamSubscription<DocumentSnapshot<Map<String, dynamic>>>? _tableSub;
  bool _isShowingSeatSwapDialog = false;

  int? movingSeatIndex;
  String? movingPlayerName;
  String? _lastWaitingEventKey;
  bool _isShowingWaitingLeaveSnack = false;
  bool _isShowingFillSeatDialog = false;

  @override
  void initState() {
    super.initState();
    tableDocRef = FirebaseFirestore.instance
        .collection('tables')
        .doc(widget.tableId);

    _tableSub = tableDocRef.snapshots().listen((snapshot) {
      final data = snapshot.data();
      if (data == null) return;
      _listenForPendingSeatSwap(data);
    });
  }

  @override
  void dispose() {
    _tableSub?.cancel();
    super.dispose();
  }

  Future<T> _runTableTransaction<T>(
    Future<T> Function(
      Transaction tx,
      DocumentSnapshot<Map<String, dynamic>> snap,
      Map<String, dynamic> data,
    ) action,
  ) async {
    final db = FirebaseFirestore.instance;

    return db.runTransaction<T>((tx) async {
      final snap = await tx.get(tableDocRef);

      if (!snap.exists) {
        throw Exception(
          tr(
            context,
            'Table not found',
            zhTw: '找不到桌子',
            zhCn: '找不到桌子',
            ko: '테이블을 찾을 수 없습니다',
            ja: 'テーブルが見つかりません',
            de: 'Tisch nicht gefunden',
            fr: 'Table introuvable',
            ar: 'لم يتم العثور على الطاولة',
            ru: 'Стол не найден',
            trk: 'Masa bulunamadı',
            es: 'Mesa no encontrada',
            it: 'Tavolo non trovato',
            pl: 'Nie znaleziono stołu',
            pt: 'Mesa não encontrada',
            th: 'ไม่พบโต๊ะ',
            id: 'Meja tidak ditemukan',
            hi: 'टेबल नहीं मिली',
            bn: 'টেবিল পাওয়া যায়নি',
          ),
        );
      }

      final data = snap.data();
      if (data == null) {
        throw Exception(
          tr(
            context,
            'Table data missing',
            zhTw: '桌子資料遺失',
            zhCn: '桌子资料缺失',
            ko: '테이블 데이터가 없습니다',
            ja: 'テーブルデータがありません',
            de: 'Tischdaten fehlen',
            fr: 'Données de table manquantes',
            ar: 'بيانات الطاولة مفقودة',
            ru: 'Данные стола отсутствуют',
            trk: 'Masa verileri eksik',
            es: 'Faltan datos de la mesa',
            it: 'Dati del tavolo mancanti',
            pl: 'Brakuje danych stołu',
            pt: 'Dados da mesa ausentes',
            th: 'ข้อมูลโต๊ะหายไป',
            id: 'Data meja hilang',
            hi: 'टेबल डेटा नहीं मिला',
            bn: 'টেবিল ডেটা নেই',
          ),
        );
      }

      return action(tx, snap, data);
    });
  }

  Never _txFail(String message) {
    throw Exception(message);
  }

  String _cleanError(Object e) {
    return e.toString().replaceFirst('Exception: ', '');
  }

  Future<void> _listenForPendingSeatSwap(Map<String, dynamic> data) async {
    if (!mounted) return;
    if (_isShowingSeatSwapDialog) return;

    final user = FirebaseAuth.instance.currentUser;
    if (user == null) return;

    final pendingRaw = data['pendingSeatSwap'];
    if (pendingRaw is! Map) return;

    final pendingSwap = Map<String, dynamic>.from(pendingRaw);
    final targetUid = (pendingSwap['targetUid'] ?? '').toString().trim();

    if (targetUid.isEmpty || targetUid != user.uid) return;

    _isShowingSeatSwapDialog = true;

    final requesterName =
        (pendingSwap['requesterName'] ??
                tr(
                  context,
                  'Another player',
                  zhTw: '另一位玩家',
                  zhCn: '另一位玩家',
                  ko: '다른 플레이어',
                  ja: '他のプレイヤー',
                  de: 'Ein anderer Spieler',
                  fr: 'Un autre joueur',
                  ar: 'لاعب آخر',
                  ru: 'Другой игрок',
                  trk: 'Başka bir oyuncu',
                  es: 'Otro jugador',
                  it: 'Un altro giocatore',
                  pl: 'Inny gracz',
                  pt: 'Outro jogador',
                  th: 'ผู้เล่นคนอื่น',
                  id: 'Pemain lain',
                  hi: 'दूसरा खिलाड़ी',
                  bn: 'অন্য একজন খেলোয়াড়',
                ))
            .toString()
            .trim();

