  Future<Map<String, dynamic>?> _showSelectPlayerDialog() async {
    final searchController = TextEditingController();
    final currentUser = FirebaseAuth.instance.currentUser;

    List<QueryDocumentSnapshot<Map<String, dynamic>>> allPlayers = [];
    List<QueryDocumentSnapshot<Map<String, dynamic>>> filteredPlayers = [];

    try {
      final currentUid = (currentUser?.uid ?? '').trim();

      final tableSnap = await tableDocRef.get();
      final tableData = tableSnap.data() ?? {};

      final rawSeats = List<dynamic>.from(tableData['seats'] ?? []);
      final waitingList = List<dynamic>.from(tableData['waitingList'] ?? []);

      final seatedUids = <String>{};
      final seatedPlayerIds = <String>{};
      final seatedNames = <String>{};

      for (final raw in rawSeats) {
        Map<String, dynamic> seat = {};

        if (raw is Map<String, dynamic>) {
          seat = Map<String, dynamic>.from(raw);
        } else if (raw is Map) {
          seat = Map<String, dynamic>.from(raw);
        }

        final uid = (seat['playerUid'] ?? '').toString().trim();

        final playerId =
            (seat['playerId'] ?? '').toString().trim().toLowerCase();

        if (uid.isNotEmpty) {
          seatedUids.add(uid);
        }

        if (playerId.isNotEmpty) {
          seatedPlayerIds.add(playerId);
        }

        final identityKey = _seatIdentityKey(seat);

        if (identityKey.isNotEmpty) {
          seatedNames.add(identityKey);
        }
      }

      final waitingIdentityKeys = waitingList
          .map((e) => normalizeWaitingEntry(e))
          .map((e) => _waitingIdentityKey(e))
          .where((e) => e.isNotEmpty)
          .toSet();

      Query<Map<String, dynamic>> query = FirebaseFirestore.instance
          .collection('users')
          .where('isActive', isEqualTo: true);

      if (currentUid.isNotEmpty) {
        query = query.where(
          'grantedHostIds',
          arrayContains: currentUid,
        );
      }

      final snapshot = await query.limit(200).get();

      int sortScore(QueryDocumentSnapshot<Map<String, dynamic>> doc) {
        final data = doc.data();

        final selectedCount = (data['hostPickCount'] ?? 0) is int
            ? (data['hostPickCount'] ?? 0) as int
            : int.tryParse(
                    (data['hostPickCount'] ?? '0').toString(),
                  ) ??
                0;

        return selectedCount;
      }

      allPlayers = snapshot.docs.where((doc) {
        final data = doc.data();

        final uid = doc.id.trim();

        final displayName =
            (data['displayName'] ?? '').toString().trim();

        final shortName =
            (data['shortName'] ?? '').toString().trim();

        final playerId =
            (data['playerId'] ?? '').toString().trim().toLowerCase();

        if (uid.isEmpty) {
          return false;
        }

        if (currentUid.isNotEmpty && uid == currentUid) {
          return false;
        }

        if (seatedUids.contains(uid)) {
          return false;
        }

        if (playerId.isNotEmpty &&
            seatedPlayerIds.contains(playerId)) {
          return false;
        }

        final identityKey = [
          uid.toLowerCase(),
          playerId,
          displayName.toLowerCase(),
          shortName.toLowerCase(),
        ].where((e) => e.isNotEmpty).join('|');

        if (identityKey.isNotEmpty &&
            seatedNames.contains(identityKey)) {
          return false;
        }

        if (identityKey.isNotEmpty &&
            waitingIdentityKeys.contains(identityKey)) {
          return false;
        }

        return true;
      }).toList();

      allPlayers.sort((a, b) {
        final scoreA = sortScore(a);
        final scoreB = sortScore(b);

        if (scoreA != scoreB) {
          return scoreB.compareTo(scoreA);
        }

        final tsA = a.data()['lastHostPickedAt'];
        final tsB = b.data()['lastHostPickedAt'];

        final timeA =
            tsA is Timestamp ? tsA.millisecondsSinceEpoch : 0;

        final timeB =
            tsB is Timestamp ? tsB.millisecondsSinceEpoch : 0;

        if (timeA != timeB) {
          return timeB.compareTo(timeA);
        }

        final nameA =
            ((a.data()['shortName'] ??
                        a.data()['displayName'] ??
                        '')
                    .toString())
                .toLowerCase();

        final nameB =
            ((b.data()['shortName'] ??
                        b.data()['displayName'] ??
                        '')
                    .toString())
                .toLowerCase();

        return nameA.compareTo(nameB);
      });

      filteredPlayers =
          List<QueryDocumentSnapshot<Map<String, dynamic>>>.from(
        allPlayers,
      );
    } catch (e) {
      _showSnack(
        tr(
          context,
          'Failed to load players',
          zhTw: '載入玩家失敗',
          zhCn: '加载玩家失败',
          ko: '플레이어를 불러오지 못했습니다',
          ja: 'プレイヤーの読み込みに失敗しました',
          de: 'Spieler konnten nicht geladen werden',
          fr: 'Impossible de charger les joueurs',
          ar: 'فشل تحميل اللاعبين',
          ru: 'Не удалось загрузить игроков',
          trk: 'Oyuncular yüklenemedi',
          es: 'No se pudieron cargar los jugadores',
          it: 'Impossibile caricare i giocatori',
          pl: 'Nie udało się załadować graczy',
          pt: 'Falha ao carregar jogadores',
          th: 'โหลดผู้เล่นไม่สำเร็จ',
          id: 'Gagal memuat pemain',
          hi: 'खिलाड़ियों को लोड करने में विफल',
          bn: 'খেলোয়াড় লোড করা যায়নি',
        ),
      );

      return null;
    }

    if (!mounted) {
      return null;
    }

    return showDialog<Map<String, dynamic>>(
      context: context,
      builder: (context) {
        return StatefulBuilder(
          builder: (context, setDialogState) {
            void runFilter(String rawKeyword) {
              final keyword = rawKeyword.trim().toLowerCase();

              final result = allPlayers.where((doc) {
                final data = doc.data();

                final displayName =
                    (data['displayName'] ?? '')
                        .toString()
                        .toLowerCase();

                final lastName =
                    (data['lastName'] ?? '')
                        .toString()
                        .toLowerCase();

                final shortName =
                    (data['shortName'] ?? '')
                        .toString()
                        .toLowerCase();

                final playerId =
                    (data['playerId'] ?? '')
                        .toString()
                        .toLowerCase();

                final email =
                    (data['email'] ?? '')
                        .toString()
                        .toLowerCase();

                if (keyword.isEmpty) {
                  return true;
                }

                return displayName.contains(keyword) ||
                    lastName.contains(keyword) ||
                    shortName.contains(keyword) ||
                    playerId.contains(keyword) ||
                    email.contains(keyword);
              }).toList();

              result.sort((a, b) {
                final scoreA =
                    ((a.data()['hostPickCount'] ?? 0) is int)
                        ? (a.data()['hostPickCount'] ?? 0)
                            as int
                        : int.tryParse(
                              (a.data()['hostPickCount'] ?? '0')
                                  .toString(),
                            ) ??
                            0;

                final scoreB =
                    ((b.data()['hostPickCount'] ?? 0) is int)
                        ? (b.data()['hostPickCount'] ?? 0)
                            as int
                        : int.tryParse(
                              (b.data()['hostPickCount'] ?? '0')
                                  .toString(),
                            ) ??
                            0;

                if (scoreA != scoreB) {
                  return scoreB.compareTo(scoreA);
                }

                final tsA = a.data()['lastHostPickedAt'];
                final tsB = b.data()['lastHostPickedAt'];

                final timeA =
                    tsA is Timestamp
                        ? tsA.millisecondsSinceEpoch
                        : 0;

                final timeB =
                    tsB is Timestamp
                        ? tsB.millisecondsSinceEpoch
                        : 0;

                if (timeA != timeB) {
                  return timeB.compareTo(timeA);
                }

                final nameA =
                    ((a.data()['shortName'] ??
                                a.data()['displayName'] ??
                                '')
                            .toString())
                        .toLowerCase();

                final nameB =
                    ((b.data()['shortName'] ??
                                b.data()['displayName'] ??
                                '')
                            .toString())
                        .toLowerCase();

                return nameA.compareTo(nameB);
              });

              setDialogState(() {
                filteredPlayers = result;
              });
            }

            return AlertDialog(
              title: Text(
                tr(
                  context,
                  'Select Player',
                  zhTw: '選擇玩家',
                  zhCn: '选择玩家',
                  ko: '플레이어 선택',
                  ja: 'プレイヤーを選択',
                  de: 'Spieler auswählen',
                  fr: 'Sélectionner un joueur',
                  ar: 'اختر لاعباً',
                  ru: 'Выберите игрока',
                  trk: 'Oyuncu Seç',
                  es: 'Seleccionar jugador',
                  it: 'Seleziona giocatore',
                  pl: 'Wybierz gracza',
                  pt: 'Selecionar jogador',
                  th: 'เลือกผู้เล่น',
                  id: 'Pilih pemain',
                  hi: 'खिलाड़ी चुनें',
                  bn: 'খেলোয়াড় নির্বাচন করুন',
                ),
              ),
              content: SizedBox(
                width: 420,
                height: 500,
                child: Column(
                  children: [
                    TextField(
