          ar: 'تمت الإزالة من قائمة الانتظار',
          ru: 'Удалено из списка ожидания',
          trk: 'Bekleme listesinden kaldırıldı',
          es: 'Eliminado de la lista de espera',
          it: 'Rimosso dalla lista d’attesa',
