          ),
        );
        return;
      }

      await _runTableTransaction<void>((tx, snap, data) async {
        final seats = normalizeSeatMaps(data['seats']);

        if (seatIndex < 0 || seatIndex >= seats.length) {
          _txFail(
            tr(
              context,
              'Invalid seat',
              zhTw: '無效座位',
              zhCn: '无效座位',
              ko: '잘못된 좌석입니다',
              ja: '無効な席です',
              de: 'Ungültiger Sitz',
