                      pl: 'Opuść miejsce',
                      pt: 'Sair do assento',
                      th: 'ออกจากที่นั่ง',
                      id: 'Tinggalkan kursi',
                      hi: 'सीट छोड़ें',
                      bn: 'সিট ছাড়ুন',
                    ),
                  ),
                  onTap: () => Navigator.pop(
                    context,
                    'leave_seat',
                  ),
                ),
                ListTile(
                  leading: const Icon(Icons.close),
                  title: Text(
                    tr(
                      context,
                      'Cancel',
                      zhTw: '取消',
                      zhCn: '取消',
                      ko: '취소',
                      ja: 'キャンセル',
                      de: 'Abbrechen',
                      fr: 'Annuler',
                      ar: 'إلغاء',
                      ru: 'Отмена',
                      trk: 'İptal',
                      es: 'Cancelar',
                      it: 'Annulla',
                      pl: 'Anuluj',
                      pt: 'Cancelar',
                      th: 'ยกเลิก',
