                    ),
                  ),
                  onTap: () => Navigator.pop(context, 'cancel'),
                ),
              ],
            ),
          );
        },
      );

      if (!mounted ||
          action == null ||
          action == 'cancel') {
        return;
      }

      if (action == 'toggle_arrived') {
        await _toggleArrivedAtSeat(seatIndex);
        return;
      }

      if (action == 'leave_seat') {
        await _cancelCurrentUserSeat(seatIndex);
        return;
      }

      return;
    }

    if (mySeatIndex == -1) {
      _showSnack(
        tr(
          context,
          'You must already be seated to request a swap',
