      );

      return;
    }

    final mySeat =
        Map<String, dynamic>.from(seatList[mySeatIndex]);

    final targetSeat =
        Map<String, dynamic>.from(seat);

    final mySeatUid =
        (mySeat['playerUid'] ?? '').toString().trim();

    final targetSeatUid =
        (targetSeat['playerUid'] ?? '').toString().trim();

    if (mySeatUid.isEmpty || targetSeatUid.isEmpty) {
      _showSnack(
