  String _formatDateTime(DateTime? dt) {
    if (dt == null) {
      return tr(
        context,
        'Not set',
        zhTw: '未設定',
        zhCn: '未设置',
        ko: '설정되지 않음',
        ja: '未設定',
        de: 'Nicht festgelegt',
        fr: 'Non défini',
        ar: 'غير محدد',
        ru: 'Не задано',
        trk: 'Ayarlanmadı',
        es: 'No establecido',
        it: 'Non impostato',
        pl: 'Nie ustawiono',
        pt: 'Não definido',
        th: 'ยังไม่ได้ตั้งค่า',
        id: 'Belum diatur',
        hi: 'सेट नहीं है',
        bn: 'সেট করা হয়নি',
      );
    }

    final hour = dt.hour == 0 ? 12 : (dt.hour > 12 ? dt.hour - 12 : dt.hour);
    final minute = dt.minute.toString().padLeft(2, '0');
    final ampm = dt.hour >= 12 ? 'PM' : 'AM';

    return '${dt.month}/${dt.day}/${dt.year}  $hour:$minute $ampm';
  }

  Color _seatFillColor({
    required bool isOpen,
    required bool isMine,
    required bool isDealerSeat,
    required bool isSelectedForMove,
    required SeatReservation seat,
  }) {
    if (isDealerSeat) {
      return const Color(0xFFFFF7ED);
    }

    if (isSelectedForMove) {
      return const Color(0xFFE5E7EB);
    }

    if (isMine) {
      return const Color(0xFFDBEAFE);
    }

    final isReserved =
        (seat.playerName?.trim().isEmpty ?? true) &&
        (
          (seat.reservedForName?.trim().isNotEmpty ?? false) ||
          (seat.reservedForUid?.trim().isNotEmpty ?? false) ||
          (seat.reservedForPlayerId?.trim().isNotEmpty ?? false)
        );

    final isArrived = isReserved
        ? (seat.reservedArrived == true)
        : (seat.arrived == true);

    if (isOpen) {
      return const Color(0xFFDCFCE7);
    }

    if (isArrived) {
      return const Color(0xFFEDE9FE);
    }

    return const Color(0xFFFEE2E2);
  }

  Color _seatBorderColor({
    required bool isOpen,
    required bool isMine,
    required bool isDealerSeat,
    required bool isSelectedForMove,
    required SeatReservation seat,
  }) {
    if (isDealerSeat) {
      return const Color(0xFFF97316);
    }

    if (isSelectedForMove) {
      return Colors.black;
    }

    if (isMine) {
      return const Color(0xFF2563EB);
    }

    final isReserved =
        (seat.playerName?.trim().isEmpty ?? true) &&
        (
          (seat.reservedForName?.trim().isNotEmpty ?? false) ||
          (seat.reservedForUid?.trim().isNotEmpty ?? false) ||
          (seat.reservedForPlayerId?.trim().isNotEmpty ?? false)
        );

    final isArrived = isReserved
        ? (seat.reservedArrived == true)
        : (seat.arrived == true);

    if (isOpen) {
      return const Color(0xFF16A34A);
    }

    if (isArrived) {
      return const Color.fromARGB(255, 200, 9, 238);
    }

    return const Color(0xFFDC2626);
  }

  Widget _buildDetailStatChip({
    required IconData icon,
    required String label,
    required String value,
    required Color color,
  }) {
    return forceLightTheme(
      Container(
        padding: const EdgeInsets.symmetric(
          horizontal: 12,
          vertical: 9,
        ),
        decoration: BoxDecoration(
          color: Colors.white,
          borderRadius: BorderRadius.circular(12),
          border: Border.all(
            color: color.withValues(alpha: 0.28),
          ),
        ),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            Icon(
              icon,
              size: 15,
              color: color,
            ),
            const SizedBox(width: 6),
            Text(
              label,
              style: TextStyle(
                color: color,
                fontWeight: FontWeight.w900,
              ),
            ),
            const SizedBox(width: 4),
            Text(
              value,
              style: const TextStyle(
                color: Colors.black87,
                fontWeight: FontWeight.w900,
              ),
            ),
          ],
        ),
      ),
    );
  }

