                    zhCn: '新增访客',
                    ko: '게스트 추가',
                    ja: 'ゲストを追加',
                    de: 'Gast hinzufügen',
                    fr: 'Ajouter un invité',
                    ar: 'إضافة ضيف',
                    ru: 'Добавить гостя',
                    trk: 'Misafir ekle',
                    es: 'Agregar invitado',
                    it: 'Aggiungi ospite',
                    pl: 'Dodaj gościa',
                    pt: 'Adicionar convidado',
                    th: 'เพิ่มแขก',
                    id: 'Tambah tamu',
                    hi: 'मेहमान जोड़ें',
