  Future<void> _addSelectedPlayerToWaitingList() async {
    final selectedPlayer = await _showSelectPlayerDialog();
    if (!mounted) return;
    if (selectedPlayer == null) return;

    final selectedUid = (selectedPlayer['uid'] ?? '').toString().trim();

    final selectedName =
        (selectedPlayer['displayName'] ??
                selectedPlayer['displayName'] ??
                '')
            .toString()
            .trim();

    final selectedShortName =
        (selectedPlayer['shortName'] ??
                selectedPlayer['displayName'] ??
                selectedName)
            .toString()
            .trim();
  
    final selectedPlayerId =
        (selectedPlayer['playerId'] ?? '').toString().trim();
  
    if (selectedName.isEmpty) {
      _showSnack(
        tr(
          context,
          'Invalid player',
          zhTw: '無效玩家',
          zhCn: '无效玩家',
          ko: '잘못된 플레이어입니다',
          ja: '無効なプレイヤーです',
          de: 'Ungültiger Spieler',
          fr: 'Joueur invalide',
          ar: 'لاعب غير صالح',
          ru: 'Недопустимый игрок',
          trk: 'Geçersiz oyuncu',
          es: 'Jugador inválido',
          it: 'Giocatore non valido',
