class SeatTableBoard extends StatelessWidget {
  final int? movingSeatIndex;
  final String tableName;
  final String currentUserName;
  final List<SeatReservation> seats;
  final ValueChanged<int> onSeatTap;
  final String? dealerName;

  const SeatTableBoard({
    super.key,
    required this.movingSeatIndex,
    required this.tableName,
    required this.currentUserName,
    required this.seats,
    required this.onSeatTap,
    this.dealerName,
  });

  bool _isMineSeat(SeatReservation seat) {
    final seatName = (seat.playerName ?? '').trim().toLowerCase();
    final seatShortName = (seat.playerShortName ?? '').trim().toLowerCase();
    final myName = currentUserName.trim().toLowerCase();

    return seatName == myName || seatShortName == myName;
  }

  List<Offset> _buildSeatOffsets(int seatCount) {
    if (seatCount == 9) {
      return const [
        Offset(0.17, 0.26),
        Offset(0.50, 0.16),
        Offset(0.83, 0.26),
        Offset(0.91, 0.48),
        Offset(0.78, 0.76),
        Offset(0.50, 0.86),
        Offset(0.22, 0.76),
        Offset(0.09, 0.48),
        Offset(0.15, 0.61),
      ];
    }

    if (seatCount == 10) {
      return const [
        Offset(0.15, 0.25),
        Offset(0.35, 0.16),
        Offset(0.65, 0.16),
        Offset(0.85, 0.25),
        Offset(0.92, 0.46),
        Offset(0.84, 0.73),
        Offset(0.65, 0.86),
        Offset(0.35, 0.86),
        Offset(0.16, 0.73),
        Offset(0.08, 0.46),
      ];
    }

    return const [
      Offset(0.15, 0.25),
      Offset(0.33, 0.15),
      Offset(0.50, 0.12),
      Offset(0.67, 0.15),
      Offset(0.85, 0.25),
      Offset(0.93, 0.46),
      Offset(0.84, 0.73),
      Offset(0.67, 0.86),
      Offset(0.50, 0.90),
      Offset(0.33, 0.86),
      Offset(0.16, 0.73),
    ];
  }

  @override
  Widget build(BuildContext context) {
    final count = seats.length;

    return LayoutBuilder(
      builder: (context, constraints) {
        final w = constraints.maxWidth;
        final h = w < 430 ? 560.0 : 650.0;
        final offsets = _buildSeatOffsets(count);

        const seatWidth = 108.0;
        const seatHeight = 96.0;

        return SizedBox(
          width: w,
          height: h,
          child: Stack(
            clipBehavior: Clip.none,
            children: [
              Positioned(
                left: w * 0.14,
                top: h * 0.31,
                child: Container(
                  width: w * 0.72,
                  height: 220,
                  decoration: BoxDecoration(
                    color: const Color(0xFF166534),
                    borderRadius: BorderRadius.circular(999),
                    border: Border.all(
                      color: const Color(0xFFD4AF37),
                      width: 5,
                    ),
                    boxShadow: const [
                      BoxShadow(
                        color: Color(0x22000000),
                        blurRadius: 18,
                        offset: Offset(0, 8),
                      ),
                    ],
                  ),
                  child: Center(
                    child: Padding(
                      padding: const EdgeInsets.symmetric(horizontal: 20),
                      child: Text(
                        tableName,
                        textAlign: TextAlign.center,
                        style: const TextStyle(
                          color: Colors.white,
                          fontSize: 22,
                          fontWeight: FontWeight.w900,
                        ),
                      ),
                    ),
                  ),
                ),
              ),
              Positioned(
                left: (w - seatWidth) / 2,
                top: h * 0.11,
                child: DealerSeatWidget(
                  dealerName: dealerName,
                  canEdit: false,
                  onTap: () {},
                ),
              ),
              for (int i = 0; i < count; i++)
                Positioned(
                  left: offsets[i].dx * w - (seatWidth / 2),
                  top: offsets[i].dy * h - (seatHeight / 2),
                  child: PlayerSeatWidget(
                    seatNumber: i + 1,
                    seat: seats[i],
                    isMine: _isMineSeat(seats[i]),
                    isMoving: movingSeatIndex == i,
                    onTap: () => onSeatTap(i),
                  ),
                ),
            ],
          ),
        );
      },
    );
  }
}

