                      trk: 'İstatistikler yüklenemedi\n\n${snapshot.error}',
                      es: 'No se pudieron cargar las estadísticas\n\n${snapshot.error}',
                      it: 'Impossibile caricare le statistiche\n\n${snapshot.error}',
                      pl: 'Nie udało się załadować statystyk\n\n${snapshot.error}',
                      pt: 'Falha ao carregar estatísticas\n\n${snapshot.error}',
                      th: 'โหลดสถิติไม่สำเร็จ\n\n${snapshot.error}',
                      id: 'Gagal memuat statistik\n\n${snapshot.error}',
                      hi: 'आँकड़े लोड करने में विफल\n\n${snapshot.error}',
                      bn: 'পরিসংখ্যান লোড ব্যর্থ\n\n${snapshot.error}',
                    ),
                    textAlign: TextAlign.center,
                    style: const TextStyle(
                      fontSize: 16,
                      fontWeight: FontWeight.w700,
                    ),
                  ),
                ),
              );
            }

            final items = (snapshot.data?.docs ?? [])
                .map(CashGameSessionItem.fromDoc)
                .toList();

            final endedItems =
                items.where((e) => !e.isOngoing && e.endedAt != null).toList();

            final totalProfit = endedItems.fold<double>(
              0,
              (total, item) => total + item.profit,
            );

            final totalHours = endedItems.fold<double>(
              0,
              (total, item) => total + item.hours,
            );

            final sessionsCount = endedItems.length;

            final hourly =
                totalHours <= 0 ? 0.0 : totalProfit / totalHours;

            final perSession =
                sessionsCount == 0 ? 0.0 : totalProfit / sessionsCount;

            final winningCount =
                endedItems.where((e) => e.profit > 0).length;

            final groupedByLocation = _buildGroupedData(
              endedItems,
              (item) => item.location.isEmpty
                  ? 'Unknown'
                  : _normalizeLocationForDisplay(item.location),
            );

            final groupedByGame = _buildGroupedData(
              endedItems,
              (item) => item.gameLabel.isEmpty ? 'Unknown' : item.gameLabel,
            );

            final groupedByWeekday = _buildGroupedData(
              endedItems,
              (item) => _weekdayZh(context, item.startedAt),
            );

            final groupedByMonth = _buildGroupedData(
              endedItems,
              (item) =>
                  '${item.startedAt.year}/${item.startedAt.month.toString().padLeft(2, '0')}',
            );

            Widget buildGroupList(Map<String, Map<String, double>> grouped) {
              final entries = grouped.entries.toList()
                ..sort((a, b) =>
                    (b.value['profit'] ?? 0).compareTo(a.value['profit'] ?? 0));

              if (entries.isEmpty) {
                return const Center(
                  child: Text(
                    'No data yet',
                    style: TextStyle(
                      color: Colors.white70,
                      fontWeight: FontWeight.w600,
                    ),
                  ),
                );
              }

              return ListView.separated(
                padding: const EdgeInsets.all(16),
                itemCount: entries.length,
                separatorBuilder: (_, __) => const SizedBox(height: 12),
                itemBuilder: (context, index) {
                  final entry = entries[index];
                  final profit = entry.value['profit'] ?? 0.0;
                  final hours = entry.value['hours'] ?? 0.0;
                  final hourly = hours <= 0 ? 0.0 : profit / hours;

                  return forceLightTheme(
                    Container(
                      padding: const EdgeInsets.all(16),
                      decoration: BoxDecoration(
                        color: Colors.white,
                        borderRadius: BorderRadius.circular(18),
                        border: Border.all(
                          color: const Color(0xFFE5E7EB),
                        ),
                      ),
                      child: Row(
                        children: [
                          Expanded(
                            child: Text(
                              entry.key,
                              style: const TextStyle(
                                color: Colors.black87,
                                fontSize: 20,
                                fontWeight: FontWeight.w900,
                              ),
                            ),
                          ),
                          const SizedBox(width: 12),
                          Column(
                            crossAxisAlignment: CrossAxisAlignment.end,
                            children: [
                              Text(
                                _moneyShortText(profit),
                                style: TextStyle(
                                  fontSize: 24,
                                  fontWeight: FontWeight.w900,
                                  color: _profitColor(profit),
                                ),
                              ),
                              const SizedBox(height: 6),
                              Container(
                                padding: const EdgeInsets.symmetric(
                                  horizontal: 12,
                                  vertical: 6,
                                ),
                                decoration: BoxDecoration(
                                  color: _profitColor(hourly),
                                  borderRadius: BorderRadius.circular(12),
                                ),
                                child: Text(
                                  '\$/${_hourText(hourly)}/hr',
                                  style: const TextStyle(
                                    color: Colors.white,
                                    fontWeight: FontWeight.w800,
                                  ),
                                ),
                              ),
                            ],
                          ),
                        ],
                      ),
                    ),
                  );
                },
              );
            }

            Widget buildAllSessions() {
              return ListView(
                padding: const EdgeInsets.all(16),
                children: [
                  GridView.count(
