  Future<void> _save() async {
    final userUid = FirebaseAuth.instance.currentUser?.uid ?? '';

    if (userUid.isEmpty) {
      return;
    }

    if (locationController.text.trim().isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            tr(
              context,
              'Enter the location',
              zhTw: '請輸入地點',
              zhCn: '请输入地点',
              ko: '장소를 입력하세요',
              ja: '場所を入力してください',
              de: 'Ort eingeben',
              fr: 'Entrez le lieu',
              ar: 'أدخل الموقع',
              ru: 'Введите место',
              trk: 'Konumu girin',
              es: 'Ingresa la ubicación',
              it: 'Inserisci la posizione',
              pl: 'Wprowadź lokalizację',
              pt: 'Digite o local',
              th: 'กรุณากรอกสถานที่',
              id: 'Masukkan lokasi',
              hi: 'स्थान दर्ज करें',
              bn: 'লোকেশন লিখুন',
            ),
          ),
        ),
      );
      return;
    }

    if (!isOngoing && endedAt == null) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            tr(
              context,
              'Choose the end time',
              zhTw: '請選擇結束時間',
              zhCn: '请选择结束时间',
              ko: '종료 시간을 선택하세요',
              ja: '終了時間を選択してください',
              de: 'Endzeit auswählen',
              fr: 'Choisissez l’heure de fin',
              ar: 'اختر وقت الانتهاء',
              ru: 'Выберите время окончания',
              trk: 'Bitiş zamanını seçin',
              es: 'Elige la hora de finalización',
              it: 'Scegli l’orario di fine',
              pl: 'Wybierz czas zakończenia',
              pt: 'Escolha o horário de término',
              th: 'กรุณาเลือกเวลาสิ้นสุด',
              id: 'Pilih waktu selesai',
              hi: 'समाप्ति समय चुनें',
              bn: 'শেষ সময় নির্বাচন করুন',
            ),
          ),
        ),
      );
      return;
    }

    setState(() {
      isSaving = true;
    });

    final formattedLocation = _buildFormattedLocation();

    final data = {
      'userUid': userUid,
      'game': gameController.text.trim(),
      'stakes': stakesController.text.trim(),
      'location': formattedLocation,
      'buyIn': _toDouble(buyInController.text.trim()),
      'cashOut': _toDouble(cashOutController.text.trim()),
      'tips': _toDouble(tipsController.text.trim()),
      'note': noteController.text.trim(),
      'startedAt': Timestamp.fromDate(startedAt),
      'endedAt': isOngoing || endedAt == null
          ? null
          : Timestamp.fromDate(endedAt!),
      'isOngoing': isOngoing,
      'updatedAt': FieldValue.serverTimestamp(),
    };

    try {
      if (widget.item == null) {
        await FirebaseFirestore.instance.collection('cash_game_sessions').add({
          ...data,
          'createdAt': FieldValue.serverTimestamp(),
        });
      } else {
        await FirebaseFirestore.instance
            .collection('cash_game_sessions')
            .doc(widget.item!.id)
            .set(data, SetOptions(merge: true));
      }

      if (!mounted) return;
      Navigator.pop(context);
    } catch (e) {
      if (!mounted) return;

      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            tr(
              context,
              'Failed to save',
              zhTw: '儲存失敗',
              zhCn: '保存失败',
              ko: '저장 실패',
              ja: '保存に失敗しました',
              de: 'Speichern fehlgeschlagen',
              fr: 'Échec de l’enregistrement',
              ar: 'فشل الحفظ',
              ru: 'Не удалось сохранить',
              trk: 'Kaydedilemedi',
              es: 'No se pudo guardar',
              it: 'Salvataggio non riuscito',
              pl: 'Nie udało się zapisać',
              pt: 'Falha ao salvar',
              th: 'บันทึกไม่สำเร็จ',
